import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"48. Rosters","description":"","frontmatter":{"title":"48. Rosters","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/hours-of-work/48-rosters.md","filePath":"ebas/has-managers-admin/common-terms/hours-of-work/48-rosters.md"}'),a={name:"ebas/has-managers-admin/common-terms/hours-of-work/48-rosters.md"};function n(i,e,l,p,d,h){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_48-rosters" tabindex="-1">48. Rosters <a class="header-anchor" href="#_48-rosters" aria-label="Permalink to &quot;48. Rosters&quot;">​</a></h1><p>This clause does not apply to Dental Assistants employed by DHSV or Ballarat Health Service.</p><p><strong>48.1</strong> A roster of at least 14 days’ duration will be posted at least 14 days before it comes into operation at each work location in a place where it may be readily seen by such Employees and the Secretary or other accredited representative of the HWU.</p><p><strong>48.2</strong> Rosters will set out the Employees’ daily ordinary hours of work, start times, finish times and meal intervals.</p><p><strong>48.3</strong> Subject to clause 48.4 below, seven days’ notice will be given of a change in roster, except in emergency situations.</p><p><strong>48.4</strong> Change of roster</p><p><strong>(a)</strong> Where the Employer requires an Employee, without seven days’ notice and outside the excepted circumstances in subclause 48.3 above, to perform ordinary duty at other times than those previously rostered, the Employee will be paid in accordance with the hours worked plus a daily change of roster allowance pursuant to Part 1 of</p><p><strong>(b)</strong> Provided that a part-time Employee who agrees to work shift(s) in addition to those already rostered will not be entitled to the Change of Roster allowance for the additional shift(s) worked.</p><p><strong>48.5</strong> An Employee may apply in writing to the Employer to have their roster fixed by the provisions of subclause 48.6 below in lieu of clauses 48.1 to 48.4 above.</p><p><strong>48.6</strong> Rosters will be fixed by mutual agreement, subject to the provisions of the Agreement.</p><p><strong>48.7</strong> An Employee may repudiate a request made under clause 48.5 at any time, by giving written notice to the Employer. In such a case the roster of the Employee will be determined according to clauses 48.1 to 48.4 from the commencement of the next full roster period, being not less than five clear days after such repudiation is received in writing by the Employer.</p><p><strong>48.8</strong> Rosters will be drawn up so as to provide at least eight hours between successive periods of ordinary duty.</p><p>Plain language terms: rostering, shift roster, duty roster, roster changes.</p>',13)])])}const u=t(a,[["render",n]]);export{m as __pageData,u as default};
